CREATE TABLE CRICKET
(NAME VARCHAR(50), CITY VARCHAR(50), AGE INT)

INSERT INTO CRICKET VALUES('Sachin Tendulkar', 'Mumbai', 30)INSERT INTO CRICKET VALUES('Rahul Dravid' ,'Bombay', 35)INSERT INTO CRICKET VALUES('M. S. Dhoni', 'Jharkhand', 31)INSERT INTO CRICKET VALUES('Suresh Raina', 'Gujarat', 30)SELECT * FROM CRICKET--LAB-3----A1--SELECT * INTO WORLDCUP FROM CRICKETSELECT * FROM WORLDCUP--A2--SELECT NAME, CITY INTO T20 FROM CRICKET WHERE 1=0SELECT * FROM T20--A3--SELECT * INTO IPL FROM CRICKET WHERE 1=0SELECT * FROM IPLCREATE TABLE EMPLOYEE
(NAME VARCHAR(50), CITY VARCHAR(50), AGE INT)

INSERT INTO EMPLOYEE VALUES('Jay Patel', 'Rajkot ', 30)INSERT INTO EMPLOYEE VALUES('Rahul Dave', 'Baroda', 35)INSERT INTO EMPLOYEE VALUES('Jeet Patel','Surat 3', 31)INSERT INTO EMPLOYEE VALUES('Vijay Raval','Rajkot', 30)SELECT * FROM EMPLOYEE--B1--SELECT * INTO EMPOYEE_DETAIL FROM EMPLOYEESELECT * FROM EMPOYEE_DETAIL--B2--SELECT NAME,CITY INTO EMPLOYEE_DATA FROM EMPLOYEE WHERE 1=0SELECT * FROM EMPLOYEE_DATA--B3-- SELECT * INTO EMPLOYEE_INFO FROM EMPLOYEE WHERE 1=0SELECT * FROM EMPLOYEE_INFO--C1--INSERT INTO EMPLOYEE_INFOSELECT * FROM EMPLOYEEWHERE CITY = 'RAJKOT'SELECT * FROM EMPLOYEE_INFO--C2--INSERT INTO EMPLOYEE_INFOSELECT * FROM EMPLOYEEWHERE AGE>32SELECT * FROM EMPLOYEE_INFO